insert into "FBG_ANALYTICS"."CASINO"."DBT_RUN_RESULTS"
         (MODEL_EXECUTION_ID,UNIQUE_ID,INVOCATION_ID,GENERATED_AT,CREATED_AT,NAME,MESSAGE,STATUS,RESOURCE_TYPE,EXECUTION_TIME,EXECUTE_STARTED_AT,EXECUTE_COMPLETED_AT,COMPILE_STARTED_AT,COMPILE_COMPLETED_AT,ROWS_AFFECTED,FULL_REFRESH,COMPILED_CODE,FAILURES,QUERY_ID,THREAD_ID,MATERIALIZATION,ADAPTER_RESPONSE) values
    ('0d6fedc4-7351-444c-be2e-615007381edb.model.dbt_casino.casino_suo_130242','model.dbt_casino.casino_suo_130242','0d6fedc4-7351-444c-be2e-615007381edb','2026-04-09 21:12:35',
  current_timestamp::timestamp
,'casino_suo_130242','SUCCESS 633','success','model',68.26607275009155,'2026-04-09T21:08:39.465342Z','2026-04-09T21:09:47.573024Z','2026-04-09T21:08:39.456924Z','2026-04-09T21:08:39.463973Z',633,False,'with bonus_campaign_opt_ins as \n(\n    select distinct\n        acco_id,\n        bonus_campaign_id,\n        convert_timezone(\'UTC\',\'America/New_York\',\n             to_timestamp(substr(OVERRIDES,regexp_instr(OVERRIDES, \'optInTime\')+10,13))\n        ) as optintime_ET,\n    case when state <> \'AVAILABLE\' then acco_id else null end as opt_in\n    from FBG_SOURCE.OSB_SOURCE.ACCOUNT_BONUSES\n    WHERE bonus_campaign_id IN (\'130242\')\n    --DATEDIFF(\'day\', DATE(MODIFIED), CURRENT_DATE()) <= 16 \n),\n\naccount_statements_date_of_bonus as\n(\n    SELECT\n        a.acco_id,\n        a.id as account_statements_id,\n        COALESCE(cast(replace(a.ext_bonus_campaign_id,\'\',null) as int),a.bonus_campaign_id) as bonus_campaign_id,\n        try_parse_json(a.additional_info):bonusOrigin::varchar as "Bonus Origin", \n        (convert_timezone(\'UTC\', \'America/New_York\', trans_date)) AS date,\n        case when a.trans = \'CASINO_CREDIT_AWARDED\' then \'bonus awarded\'\n             when a.trans = \'CASINO_CREDIT_STAKE\' then \'bonus used\' end as transaction,\n        \'casino_credit\' as promo_type,\n        abs(a.amount) amount,\n        a.bet_id,\n        parse_json(a.additional_info):accountBonusId::int as account_bonus_id\n    FROM FBG_SOURCE.OSB_SOURCE.ACCOUNT_STATEMENTS AS a\n    INNER JOIN FBG_SOURCE.OSB_SOURCE.JURISDICTIONS AS j\n        on a.jurisdictions_id = j.id\n    LEFT JOIN FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.BONUS_CATEGORIES AS B\n        ON COALESCE(cast(replace(a.ext_bonus_campaign_id,\'\',null) as int),a.bonus_campaign_id) = b.bonus_campaign_id\n    WHERE a.trans in (\'CASINO_CREDIT_AWARDED\')\n        and a.bonus_campaign_id IN (\'130244\')\n),\n\nfancash_date_of_bonus\nAS\n(\n\nselect\nacco_id,\ncpl.date,\nconvert_timezone(\'America/Anchorage\', \'America/New_York\', cpl.date) as date_est,\nsum(case when promo_type like \'fancash%\' then amount else 0 end) fc_awarded\n\nFROM FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.casino_promotions_ledger cpl\nWHERE cpl.product = \'casino\' AND cpl.bonus_campaign_id = \'130243\' AND transaction = \'bonus awarded\'\ngroup by all \n\n),\ncash_wagering AS \n(\n    SELECT \n        cba.acco_id,\n     --   oi.bonus_campaign_id,\n        cba.PLACED_TIME_EST, \n    --    oi.optintime_ET,\n        cba.stake,\n        SUM(cba.stake) OVER ( PARTITION BY cba.acco_id ORDER BY cba.PLACED_TIME_EST ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) AS cumulative_wager\n    FROM\n    FBG_ANALYTICS_ENGINEERING.CASINO.casino_transactions_mart cba\n    WHERE cba.fund_type_id = 1 AND cba.void = 0\n),\n\ntimestamp_of_10_stake\nAS\n(\nSELECT \n    acco_id,\n  --  optintime_ET,\n  --  bonus_campaign_id,\n    PLACED_TIME_EST AS reached_10_timestamp\nFROM cash_wagering\nWHERE cumulative_wager >= 10\nQUALIFY ROW_NUMBER() OVER (PARTITION BY acco_id ORDER BY PLACED_TIME_EST) = 1\n)\n\nSELECT DISTINCT \n\nbc.acco_id,\ncs.registration_state,\nbc.bonus_campaign_id,\ncs.acquisition_bonus_name,\ncs.registration_date_est as "Timestamp EST of Registration",\ncs.kyc_date_est as "Timestamp EST of KYC",\n--cs.casino_ftcu_date_est as "Timestamp EST of Casino First Time Cash Date",\n\nbc.optintime_ET as "Timestamp EST of Opt In",\nts.reached_10_timestamp as "Timestamp EST of $10 Casino Cash Wagering",\n\nab.date as "Timestamp EST of Casino Credit Awarded",\nfd.date_est as "Timestamp EST of Fancash Awarded",\n\nCASE WHEN "Timestamp EST of $10 Casino Cash Wagering" is NULL THEN FALSE ELSE TRUE END as "Wager Requirement T/F",\nCASE WHEN "Timestamp EST of Casino Credit Awarded" is NULL THEN FALSE ELSE TRUE END as "Casino Credit Awarded T/F",\nCASE WHEN "Timestamp EST of Fancash Awarded" is NULL THEN FALSE ELSE TRUE END as "Fancash Awarded T/F",\n\n--DATEDIFF(\'seconds\', "Timestamp EST of $10 Casino Cash Wagering", "Timestamp EST of Free Spin Awarded") as "Time Between Reaching $10 Wager & Awarded Free Spin",\n\nFROM\nbonus_campaign_opt_ins bc\nLEFT JOIN timestamp_of_10_stake ts\n    ON bc.acco_id = ts.acco_id\nLEFT JOIN FBG_ANALYTICS_ENGINEERING.CUSTOMERS.customer_mart cs \n    ON bc.acco_id = cs.acco_id\nLEFT JOIN account_statements_date_of_bonus ab \n    ON bc.acco_id = ab.acco_id\nLEFT JOIN fancash_date_of_bonus fd\n    on bc.acco_id = fd.acco_id\nWHERE cs.is_test_account = 0',NULL,'01c399f4-0212-67a9-24dd-07031931e1fb','Thread-8 (worker)','table','{"_message": "SUCCESS 633", "code": "SUCCESS", "rows_affected": 633, "query_id": "01c399f4-0212-67a9-24dd-07031931e1fb", "rows_inserted": 633, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('0d6fedc4-7351-444c-be2e-615007381edb.model.dbt_casino.casino_suo_30_50_cc','model.dbt_casino.casino_suo_30_50_cc','0d6fedc4-7351-444c-be2e-615007381edb','2026-04-09 21:12:35',
  current_timestamp::timestamp
,'casino_suo_30_50_cc','SUCCESS 60547','success','model',92.08733677864075,'2026-04-09T21:08:39.467821Z','2026-04-09T21:10:11.359501Z','2026-04-09T21:08:39.460235Z','2026-04-09T21:08:39.464434Z',60547,False,'WITH bonus_campaign_opt_ins AS \n(\n    SELECT DISTINCT\n        acco_id,\n        bonus_campaign_id,\n        CONVERT_timezone(\'UTC\',\'America/New_York\',\n             TO_TIMESTAMP(SUBSTR(overrides, REGEXP_INSTR(overrides, \'optInTime\')+10, 13))\n        ) AS optintime_ET,\n        CASE WHEN state <> \'AVAILABLE\' THEN acco_id ELSE NULL END AS opt_in\n    FROM FBG_SOURCE.OSB_SOURCE.ACCOUNT_BONUSES\n    WHERE bonus_campaign_id IN (\'105973\',\'105982\',\'105983\')\n),\n\naccount_statements_date_of_bonus AS\n(\n    SELECT\n        a.acco_id,\n        a.id AS account_statements_id,\n        COALESCE(\n            CAST(NULLIF(a.ext_bonus_campaign_id, \'\') AS INT),\n            a.bonus_campaign_id\n        ) AS bonus_campaign_id,\n        TRY_PARSE_JSON(a.additional_info):bonusOrigin::VARCHAR AS bonus_origin, \n        CONVERT_timezone(\'UTC\',\'America/New_York\', a.trans_date) AS date,\n        CASE \n            WHEN a.trans = \'CASINO_CREDIT_AWARDED\' THEN \'bonus awarded\'\n            WHEN a.trans = \'CASINO_CREDIT_STAKE\'   THEN \'bonus used\'\n        END AS transaction,\n        \'casino_credit\' AS promo_type,\n        ABS(a.amount) AS amount,\n        a.bet_id,\n        PARSE_JSON(a.additional_info):accountBonusId::INT AS account_bonus_id\n    FROM FBG_SOURCE.OSB_SOURCE.ACCOUNT_STATEMENTS AS a\n    INNER JOIN FBG_SOURCE.OSB_SOURCE.JURISDICTIONS AS j\n        ON a.jurisdictions_id = j.id\n    LEFT JOIN fbg_analytics.product_and_customer.bonus_categories AS b\n        ON COALESCE(\n               CAST(NULLIF(a.ext_bonus_campaign_id, \'\') AS INT),\n               a.bonus_campaign_id\n           ) = b.bonus_campaign_id\n    WHERE a.trans = \'CASINO_CREDIT_AWARDED\'\n      AND a.bonus_campaign_id IN (\'105976\', \'105982\', \'105983\')\n),\ncash_wagering AS \n(\n    SELECT \n        cba.acco_id,\n  --      oi.bonus_campaign_id,\n        cba.placed_time_est,\n  --      oi.optintime_ET,\n        cba.stake,\n        SUM(cba.stake) OVER (\n            PARTITION BY cba.acco_id \n            ORDER BY cba.placed_time_est \n            ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW\n        ) AS cumulative_wager\n    FROM \n    FBG_ANALYTICS_ENGINEERING.CASINO.casino_transactions_mart AS cba\n    --    ON cba.acco_id = oi.acco_id\n    WHERE cba.fund_type_id = 1 AND cba.void = 0\n),\n\ntimestamp_of_30_stake AS \n(\n  SELECT\n    acco_id,\n    MIN(\n      CASE \n        WHEN cumulative_wager >= 30 THEN placed_time_est \n        ELSE NULL \n      END\n    ) AS reached_30_timestamp\n  FROM cash_wagering\n  GROUP BY acco_id\n),\n\nopt_in_pivot AS\n(\n    SELECT\n        acco_id,\n        MAX(CASE WHEN bonus_campaign_id = \'105973\' THEN optintime_ET END) AS optin_105973,\n        MAX(CASE WHEN bonus_campaign_id = \'105982\' THEN optintime_ET END) AS optin_105982,\n        MAX(CASE WHEN bonus_campaign_id = \'105983\' THEN optintime_ET END) AS optin_105983\n    FROM bonus_campaign_opt_ins\n    GROUP BY acco_id\n),\n\ncasino_credit_awarded_pivot AS\n(\n\nSELECT\n    acco_id,\n    MAX(CASE WHEN bonus_campaign_id = \'105982\' THEN date END) AS awarded_105982,\n    MAX(CASE WHEN bonus_campaign_id = \'105983\' THEN date END) AS awarded_105983\n\nFROM \naccount_statements_date_of_bonus\ngroup by acco_id\n\n)\n\nSELECT\n    DISTINCT\n    oip.acco_id,\n    oip.optin_105973 AS "Timestamp EST of Opt In to 105973",\n    \n    oip.optin_105982 AS "Timestamp EST of Opt In to 105982",\n    oip.optin_105983 AS "Timestamp EST of Opt In to 105983",\n\n    CASE WHEN "Timestamp EST of Opt In to 105982" is NULL THEN FALSE ELSE TRUE END as "Day 2 OptedIn T/F",\n    CASE WHEN "Timestamp EST of Opt In to 105983" is NULL THEN FALSE ELSE TRUE END as "Day 3 OptedIn T/F",\n\n    CASE WHEN ts.reached_30_timestamp is NULL THEN FALSE ELSE TRUE END as "Day 1 Wager Requirement T/F",\n\n --   cca.awarded_105982,\n --   cca.awarded_105983,\n\n    CASE WHEN cca.awarded_105982 is NULL THEN FALSE ELSE TRUE END as "Day 2 Awarded T/F",\n    CASE WHEN cca.awarded_105983 is NULL THEN FALSE ELSE TRUE END as "Day 3 Awarded T/F",\n    \n    oi.bonus_campaign_id,\n    cs.acquisition_bonus_name,\n    cs.registration_date_est        AS "Timestamp EST of Registration",\n    cs.kyc_date_est                 AS "Timestamp EST of KYC",\n    cs.casino_ftcu_date_est         AS "Timestamp EST of Casino First Time Cash Date",\n    ts.reached_30_timestamp         AS "Timestamp EST of $30 Casino Cash Wagering",\n --   ab.date                         AS "Timestamp EST of $50 CC Awarded",\n\n \nFROM bonus_campaign_opt_ins oi\nINNER JOIN opt_in_pivot oip\n    on oi.acco_id = oip.acco_id\nLEFT JOIN timestamp_of_30_stake ts\n     ON oip.acco_id = ts.acco_id\nINNER JOIN FBG_ANALYTICS_ENGINEERING.CUSTOMERS.customer_mart cs\n    ON oip.acco_id = cs.acco_id\nLEFT JOIN casino_credit_awarded_pivot cca\n    ON ts.acco_id = cca.acco_id\nWHERE cs.is_test_account = 0',NULL,'01c399f4-0212-6e7d-24dd-07031931c203','Thread-9 (worker)','table','{"_message": "SUCCESS 60547", "code": "SUCCESS", "rows_affected": 60547, "query_id": "01c399f4-0212-6e7d-24dd-07031931c203", "rows_inserted": 60547, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('0d6fedc4-7351-444c-be2e-615007381edb.model.dbt_casino.fancash_jackpot_group_optin_history','model.dbt_casino.fancash_jackpot_group_optin_history','0d6fedc4-7351-444c-be2e-615007381edb','2026-04-09 21:12:35',
  current_timestamp::timestamp
,'fancash_jackpot_group_optin_history','SUCCESS 966328','success','model',7.149371862411499,'2026-04-09T21:10:11.543545Z','2026-04-09T21:10:18.549552Z','2026-04-09T21:10:11.537676Z','2026-04-09T21:10:11.542932Z',966328,False,'-- 1. First start timestamp per group\nWITH jackpot_group_window AS (\n  SELECT\n      st.jackpot_group_id,\n      MIN(st.event_timestamp_alk)::TIMESTAMP_NTZ                    AS group_start_timestamp_alk,\n      MIN(CONVERT_TIMEZONE(\n            \'UTC\',\n            \'America/New_York\',\n            st.event_timestamp_utc::TIMESTAMP_NTZ\n        ))                                                          AS group_start_timestamp_est\n  FROM FBG_ANALYTICS_ENGINEERING.STAGING.STG_FANCASH_JACKPOT_EVENT_START st\n  WHERE  NOT REGEXP_LIKE(st.jackpot_group_id, \'[{}]\')\n  GROUP BY st.jackpot_group_id\n),\n\n-- 2 Per-instance start joined to its drop (if any)\ninstance_status AS (\n  SELECT\n      st.jackpot_group_id,\n      st.jackpot_instance_id,\n      st.jackpot_id,\n      st.jackpot_instance,\n      MIN(st.event_timestamp_alk)::TIMESTAMP_NTZ                    AS instance_start_alk,\n      MIN(CONVERT_TIMEZONE(\n            \'UTC\',\n            \'America/New_York\',\n            st.event_timestamp_utc::TIMESTAMP_NTZ\n        ))                                                          AS instance_start_est,\n      /* if dropped, capture its drop time */\n      MAX(d.event_timestamp_alk)::TIMESTAMP_NTZ                     AS instance_drop_alk,\n      MAX(CONVERT_TIMEZONE(\n            \'UTC\',\n            \'America/New_York\',\n            d.event_timestamp_utc::TIMESTAMP_NTZ\n        ))                                                          AS instance_drop_est\n  FROM FBG_ANALYTICS_ENGINEERING.STAGING.STG_FANCASH_JACKPOT_EVENT_START st\n  LEFT JOIN FBG_ANALYTICS_ENGINEERING.STAGING.STG_FANCASH_JACKPOT_EVENT_DROP d\n         ON d.jackpot_instance_id = st.jackpot_instance_id\n  WHERE NOT REGEXP_LIKE(st.jackpot_group_id, \'[{}]\')\n  GROUP BY ALL\n),\n\n-- 3 identify the latest status per jackpot_group_id\ngroup_rollup AS (\n  SELECT\n      ists.jackpot_group_id,\n\n      /* true if there\'s at least one instance without a drop */\n      MAX(CASE WHEN ists.instance_drop_alk IS NULL THEN 1 ELSE 0 END) AS open_flag_int,\n      MAX(CASE WHEN ists.instance_drop_est IS NULL THEN 1 ELSE 0 END) AS open_flag_int_est,\n\n      /* the start of the CURRENT open window = the earliest start among open instances */\n      MIN(IFF(ists.instance_drop_alk IS NULL, ists.instance_start_alk, NULL)) AS open_window_start,\n      MIN(IFF(ists.instance_drop_est IS NULL, ists.instance_start_est, NULL)) AS open_window_start_est,\n\n      /* latest close across instances (useful for reference) */\n      MAX(ists.instance_drop_alk) AS last_close_timestamp_alk,\n      MAX(ists.instance_drop_est) AS last_close_timestamp_est\n  FROM instance_status AS ists\n  GROUP BY ists.jackpot_group_id\n),\n\n-- 4) Final open window per group (only meaningful when open_flag = 1)\njackpot_open_window AS (\n  SELECT\n      gr.jackpot_group_id,\n      gw.group_start_timestamp_alk,\n      gw.group_start_timestamp_est,\n      (gr.open_flag_int = 1)                                                            AS open_jackpot_group_flag,\n      (gr.open_flag_int_est=1)                                                          AS open_jackpot_group_flag_est,\n      /* window start only if open; else NULL */\n      IFF(gr.open_flag_int = 1, gr.open_window_start, NULL)                             AS open_window_start,\n      IFF(gr.open_flag_int_est = 1, gr.open_window_start_est, NULL)                     AS open_window_start_est,\n      /* when open, "window end" is open-ended far-future; else NULL */\n      IFF(gr.open_flag_int = 1, TO_TIMESTAMP_NTZ(\'2099-01-01 00:00:00\'), NULL)          AS open_window_end,\n      IFF(gr.open_flag_int_est = 1, TO_TIMESTAMP_NTZ(\'2099-01-01 00:00:00\'), NULL)      AS open_window_end_est,\n      gr.last_close_timestamp_alk,\n      gr.last_close_timestamp_est\n  FROM group_rollup gr\n  LEFT JOIN jackpot_group_window gw\n    ON gw.jackpot_group_id = gr.jackpot_group_id\n)\n\n/* 1) Bring in raw opt-in history with deterministic ordering fields */\n, opt_in_source AS (\n    SELECT\n        o.id,\n        o.ext_jackpot_group_id AS jackpot_group_id,\n        o.acco_id,\n        o.is_opted_in,\n        o.contribution_percentage,\n        o.change_timestamp::TIMESTAMP_NTZ AS change_timestamp\n    FROM FBG_SOURCE.OSB_SOURCE.FANCASH_JACKPOT_OPTIN_HISTORY  o\n    WHERE COALESCE(o.is_deleted, FALSE) = FALSE\n      AND o.ext_jackpot_group_id IS NOT NULL\n),\n\n/* 2) Remove exact duplicate opt-in events while preserving the latest copy */\nopt_in_deduped AS (\n    SELECT\n        s.*\n    FROM opt_in_source s\n    QUALIFY ROW_NUMBER() OVER (\n        PARTITION BY\n            s.acco_id,\n            s.jackpot_group_id,\n            s.change_timestamp,\n            s.is_opted_in,\n            s.contribution_percentage\n        ORDER BY s.change_timestamp DESC\n    ) = 1\n)\n\n/* 3) Build base rows with stable sort keys */\n,opt_in_base AS (\n  SELECT \n    o.acco_id,\n    o.jackpot_group_id,\n    o.change_timestamp,\n    CONVERT_TIMEZONE(\'UTC\',\'America/Anchorage\', o.change_timestamp)                         as change_timestamp_alk,\n    date_trunc(\'day\',CONVERT_TIMEZONE(\'UTC\',\'America/Anchorage\', o.change_timestamp))       as change_date_alk,\n    CONVERT_TIMEZONE(\'UTC\',\'America/New_York\', o.change_timestamp)                          as change_timestamp_est,\n    date_trunc(\'day\',CONVERT_TIMEZONE(\'UTC\',\'America/New_York\', o.change_timestamp))        as change_date_est,\n    o.is_opted_in,\n    o.contribution_percentage,\n    -- flag a boundary when the status changes (or first row)\n    CASE\n    WHEN LAG(o.is_opted_in) OVER (PARTITION BY o.acco_id, o.jackpot_group_id ORDER BY o.change_timestamp) IS DISTINCT FROM is_opted_in\n           OR LAG(o.is_opted_in) OVER (PARTITION BY o.acco_id, o.jackpot_group_id ORDER BY o.change_timestamp) IS NULL\n    THEN 1 ELSE 0\n    END                                                                                     as is_change\n    \n  FROM opt_in_deduped o\n)\n\n,opt_in_runs AS (\n  SELECT\n    ob.acco_id,\n    ob.change_timestamp_alk,\n    ob.change_date_alk,\n    ob.change_timestamp_est,\n    ob.change_date_est,\n    ob.is_opted_in,\n    ob.jackpot_group_id,\n    ob.contribution_percentage,\n    /* run_id increments at each change */\n    SUM(ob.is_change) OVER (\n      PARTITION BY \n      ob.acco_id, ob.jackpot_group_id\n      ORDER BY ob.change_timestamp_alk\n      ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW\n    )                                                                                       AS run_id,\n    SUM(ob.is_change) OVER (\n      PARTITION BY \n      ob.acco_id, ob.jackpot_group_id\n      ORDER BY ob.change_timestamp_est\n      ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW\n    )                                                                                       AS run_id_est\n  FROM opt_in_base ob\n)\n\n,final_opt_ins as (\n    SELECT\n    r.acco_id,\n    r.is_opted_in,\n    r.jackpot_group_id,\n    r.run_id,\n    r.contribution_percentage,\n    MIN(r.change_timestamp_alk)                                                     AS start_opt_in_timestamp_alk,\n    MIN(r.change_date_alk)                                                          AS start_opt_in_date_alk,\n    MIN(r.change_timestamp_est)                                                     AS start_opt_in_timestamp_est,\n    MIN(r.change_date_est)                                                          AS start_opt_in_date_est,\n    COALESCE(LEAD(MIN(r.change_timestamp_alk)) \n        OVER (PARTITION BY r.acco_id, r.jackpot_group_id ORDER BY MIN(r.change_timestamp_alk)),\n        TO_TIMESTAMP_NTZ(\'2099-01-01 00:00:00\'))                                    AS end_opt_in_timestamp_alk,\n    COALESCE(LEAD(MIN(r.change_date_alk)) \n        OVER (PARTITION BY r.acco_id, r.jackpot_group_id ORDER BY MIN(r.change_date_alk)),\n        TO_TIMESTAMP_NTZ(\'2099-01-01 00:00:00\'))                                    AS end_opt_in_date_alk,\n    COALESCE(LEAD(MIN(r.change_timestamp_est)) \n        OVER (PARTITION BY r.acco_id, r.jackpot_group_id ORDER BY MIN(r.change_timestamp_est)),\n        TO_TIMESTAMP_NTZ(\'2099-01-01 00:00:00\'))                                    AS end_opt_in_timestamp_est,\n    COALESCE(LEAD(MIN(r.change_date_est)) \n        OVER (PARTITION BY r.acco_id, r.jackpot_group_id ORDER BY MIN(r.change_date_est)),\n        TO_TIMESTAMP_NTZ(\'2099-01-01 00:00:00\'))                                    AS end_opt_in_date_est\n    FROM opt_in_runs r\n    GROUP BY ALL\n)\n\n,opt_in_with_flags AS (\n    SELECT\n        f.*,\n\n        /* ALK: previous status for this user + group, ordered by start time */\n        LAG(f.is_opted_in) OVER (\n            PARTITION BY f.acco_id, f.jackpot_group_id\n            ORDER BY f.start_opt_in_timestamp_alk\n        )                                                                   AS prev_is_opted_in,\n\n        /* has the user/group ever been opted in before this range? */\n        COALESCE(\n            MAX(IFF(f.is_opted_in, 1, 0)) OVER (\n                PARTITION BY f.acco_id, f.jackpot_group_id\n                ORDER BY f.start_opt_in_timestamp_alk\n                ROWS BETWEEN UNBOUNDED PRECEDING AND 1 PRECEDING\n            ),\n            0\n        )                                                                   AS ever_opted_in_before,\n\n        /* est: previous status for this user + group, ordered by start time */\n        LAG(f.is_opted_in) OVER (\n            PARTITION BY f.acco_id, f.jackpot_group_id\n            ORDER BY f.start_opt_in_timestamp_est\n        )                                                                   AS prev_is_opted_in_est,\n\n        /* has the user/group ever been opted in before this range? */\n        COALESCE(\n            MAX(IFF(f.is_opted_in, 1, 0)) OVER (\n                PARTITION BY f.acco_id, f.jackpot_group_id\n                ORDER BY f.start_opt_in_timestamp_est\n                ROWS BETWEEN UNBOUNDED PRECEDING AND 1 PRECEDING\n            ),\n            0\n        )                                                                   AS ever_opted_in_before_est\n    FROM final_opt_ins f\n)\n\n, opt_in_ranges as (\nSELECT\n    f.acco_id,\n    f.jackpot_group_id,\n    f.is_opted_in,\n    f.contribution_percentage,\n    f.start_opt_in_timestamp_alk,\n    f.start_opt_in_date_alk,\n    f.start_opt_in_timestamp_est,\n    f.start_opt_in_date_est,\n    /* End opt-in date is whichever comes first: user\'s opt_out or group\'s closure */\n    LEAST(\n      f.end_opt_in_timestamp_alk,\n      COALESCE(\n        IFF(j.open_jackpot_group_flag, TO_TIMESTAMP_NTZ(\'2099-01-01 00:00:00\'), j.last_close_timestamp_alk),\n        f.end_opt_in_timestamp_alk\n      )\n    )                                                                                                               AS end_opt_in_timestamp_alk,\n     LEAST(\n      f.end_opt_in_date_alk,\n      COALESCE(\n        IFF(j.open_jackpot_group_flag, TO_TIMESTAMP_NTZ(\'2099-01-01 00:00:00\'), j.last_close_timestamp_alk),\n        f.end_opt_in_date_alk\n      )\n    )                                                                                                               AS end_opt_in_date_alk,\n     LEAST(\n      f.end_opt_in_timestamp_est,\n      COALESCE(\n        IFF(j.open_jackpot_group_flag, TO_TIMESTAMP_NTZ(\'2099-01-01 00:00:00\'), j.last_close_timestamp_est),\n        f.end_opt_in_timestamp_est\n      )\n    )                                                                                                               AS end_opt_in_timestamp_est,\n     LEAST(\n      f.end_opt_in_date_est,\n      COALESCE(\n        IFF(j.open_jackpot_group_flag, TO_TIMESTAMP_NTZ(\'2099-01-01 00:00:00\'), j.last_close_timestamp_est),\n        f.end_opt_in_date_est\n      )\n    )                                                                                                               AS end_opt_in_date_est,\n    j.group_start_timestamp_alk,\n    j.last_close_timestamp_alk,\n    j.group_start_timestamp_est,\n    j.last_close_timestamp_est,\n    j.open_jackpot_group_flag,\n    f.prev_is_opted_in,\n    f.ever_opted_in_before,\n    f.prev_is_opted_in_est,\n    f.ever_opted_in_before_est,\n\n    /* based on ALK */\n    /* 1 = winback, 0 = not */\n    CASE\n        WHEN f.is_opted_in = TRUE\n            AND COALESCE(f.prev_is_opted_in, FALSE) = FALSE       -- immediate prior range was NOT opted in\n            AND f.ever_opted_in_before = 1                        -- there WAS at least one earlier TRUE\n        THEN 1\n        ELSE 0\n    END                                                                                                         AS winback_flag,\n\n    /* first-ever opt-in flag */\n    CASE\n        WHEN f.is_opted_in = TRUE\n            AND f.ever_opted_in_before = 0\n        THEN 1\n        ELSE 0\n    END                                                                                                        AS first_opt_in_flag,\n    /*based on EST*/\n    CASE\n        WHEN f.is_opted_in = TRUE\n            AND COALESCE(f.prev_is_opted_in_est, FALSE) = FALSE       -- immediate prior range was NOT opted in\n            AND f.ever_opted_in_before_est = 1                        -- there WAS at least one earlier TRUE\n        THEN 1\n        ELSE 0\n    END                                                                                                         AS winback_flag_est,\n\n    /* first-ever opt-in flag */\n    CASE\n        WHEN f.is_opted_in = TRUE\n            AND f.ever_opted_in_before_est = 0\n        THEN 1\n        ELSE 0\n    END                                                                                                        AS first_opt_in_flag_est\nFROM opt_in_with_flags f\nLEFT JOIN jackpot_open_window j\n  ON f.jackpot_group_id = j.jackpot_group_id\n)\n\nSELECT\n    r.*\nFROM opt_in_ranges r',NULL,'01c399f6-0212-6dbe-24dd-070319320a5f','Thread-9 (worker)','table','{"_message": "SUCCESS 966328", "code": "SUCCESS", "rows_affected": 966328, "query_id": "01c399f6-0212-6dbe-24dd-070319320a5f", "rows_inserted": 966328, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('0d6fedc4-7351-444c-be2e-615007381edb.model.dbt_casino.casino_suo_1000fs','model.dbt_casino.casino_suo_1000fs','0d6fedc4-7351-444c-be2e-615007381edb','2026-04-09 21:12:35',
  current_timestamp::timestamp
,'casino_suo_1000fs','SUCCESS 45080','success','model',130.5495867729187,'2026-04-09T21:08:39.470272Z','2026-04-09T21:10:49.877455Z','2026-04-09T21:08:39.453122Z','2026-04-09T21:08:39.466677Z',45080,False,'WITH bonus_campaign_opt_ins AS ---Reg ID\n(\n    SELECT DISTINCT \n        acco_id,\n        bonus_campaign_id,\n        CONVERT_TIMEZONE(\'UTC\',\'America/New_York\',\n            TO_TIMESTAMP(\n              SUBSTR(overrides, REGEXP_INSTR(overrides,\'optInTime\')+10,13)\n            )\n        ) AS optintime_ET,\n        CASE WHEN state <> \'AVAILABLE\' THEN acco_id ELSE NULL END AS opt_in\n    FROM FBG_SOURCE.OSB_SOURCE.ACCOUNT_BONUSES\n    WHERE bonus_campaign_id IN (\'152889\', \'152890\', \'153565\', \'153572\', \'153611\', \'153614\')\n\n\n),\n\nopt_in_sequenced as \n(\n\nSELECT\n    acco_id,\n    bonus_campaign_id,\n    CONVERT_TIMEZONE(\'UTC\',\'America/New_York\', TO_TIMESTAMP(SUBSTR(overrides, REGEXP_INSTR(overrides,\'optInTime\')+10,13))) AS date,\nFROM FBG_SOURCE.OSB_SOURCE.ACCOUNT_BONUSES a\nWHERE \na.bonus_campaign_id IN (\n        -- Day 1\n        \'153560\', \'153588\', \'153617\', \n        -- Day 2\n        \'153561\',\'153589\', \'153619\',\n        -- Day 3\n        \'153562\',\'153590\', \'153622\', \n        -- Day 4\n        \'153563\',\'153592\', \'153625\', \n        -- Day 5\n        \'153564\',\'153593\', \'153626\'\n        )\nAND state <> \'AVAILABLE\' AND state = \'EXECUTED\' AND (OVERRIDES LIKE \'%optInTime%\')\n\n),\n\naccount_statements_free_spins\nAS\n(\n    SELECT\n        a.acco_id,\n        COALESCE(\n          CAST(NULLIF(a.ext_bonus_campaign_id,\'\') AS INT),\n          a.bonus_campaign_id\n        ) AS bonus_campaign_id,\n        CONVERT_TIMEZONE(\'UTC\',\'America/New_York\', a.trans_date) AS date\n    FROM FBG_SOURCE.OSB_SOURCE.ACCOUNT_STATEMENTS AS a\n    INNER JOIN FBG_SOURCE.OSB_SOURCE.JURISDICTIONS AS j\n        ON a.jurisdictions_id = j.id\n    WHERE a.trans = \'FREE_SPIN_AWARDED\' AND \n    a.bonus_campaign_id IN \n    (\n        -- Day 1\n        \'153560\', \'153588\', \'153617\', \n        -- Day 2\n        \'153561\',\'153589\', \'153619\',\n        -- Day 3\n        \'153562\',\'153590\', \'153622\', \n        -- Day 4\n        \'153563\',\'153592\', \'153625\', \n        -- Day 5\n        \'153564\',\'153593\', \'153626\'\n    )\n),\ncash_wagering AS \n(\n    SELECT \n        cba.acco_id,\n        cba.placed_time_est,\n        cba.stake,\n        SUM(cba.stake) \n          OVER (\n            PARTITION BY cba.acco_id \n            ORDER BY cba.placed_time_est \n            ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW\n          ) AS cumulative_wager\n    FROM FBG_ANALYTICS_ENGINEERING.CASINO.casino_transactions_mart AS cba\n    WHERE cba.fund_type_id = 1\n      AND cba.void = 0\n),\n\ntimestamp_of_10_stake AS\n(\n    SELECT \n        cash_wagering.acco_id,\n        placed_time_est AS reached_10_timestamp,\n        CASE WHEN reached_10_timestamp = NULL THEN FALSE ELSE TRUE end as reached_timestamp \n    \n        \n    FROM cash_wagering\n    WHERE cumulative_wager >= 10\n    QUALIFY ROW_NUMBER() \n      OVER (PARTITION BY cash_wagering.acco_id ORDER BY placed_time_est) = 1\n),\n\nfree_spin_pivot_awarded AS\n(\n    SELECT\n        acco_id,\n        MAX(CASE WHEN bonus_campaign_id IN (\'153560\', \'153588\', \'153617\')  THEN date END) AS day1_awarded,\n        MAX(CASE WHEN bonus_campaign_id IN (\'153561\',\'153589\', \'153619\') THEN date END) AS day2_awarded,\n        MAX(CASE WHEN bonus_campaign_id IN (\'153562\',\'153590\', \'153622\') THEN date END) AS day3_awarded,\n        MAX(CASE WHEN bonus_campaign_id IN (\'153563\',\'153592\', \'153625\') THEN date END) AS day4_awarded,\n        MAX(CASE WHEN bonus_campaign_id IN (\'153564\',\'153593\', \'153626\') THEN date END) AS day5_awarded\n    FROM account_statements_free_spins\n    GROUP BY acco_id\n),\n\nfree_spin_pivot_optedin AS\n(\n\nSELECT\n    acco_id,\n    MAX(CASE WHEN bonus_campaign_id IN (\'153560\', \'153588\', \'153617\') THEN date END) AS day1_optedin,\n    MAX(CASE WHEN bonus_campaign_id IN (\'153561\',\'153589\', \'153619\') THEN date END) AS day2_optedin,\n    MAX(CASE WHEN bonus_campaign_id IN (\'153562\',\'153590\', \'153622\') THEN date END) AS day3_optedin,\n    MAX(CASE WHEN bonus_campaign_id IN (\'153563\',\'153592\', \'153625\') THEN date END) AS day4_optedin,\n    MAX(CASE WHEN bonus_campaign_id IN (\'153564\',\'153593\', \'153626\') THEN date END) AS day5_optedin\n\nFROM \nopt_in_sequenced\ngroup by all \n\n)\n\n\nSELECT\n\n\n    bc.acco_id,\n    bc.bonus_campaign_id,\n    cs.registration_state,\n    cs.acquisition_bonus_name,\n    \n    cs.registration_date_est as "Timestamp EST of Registration",\n    cs.kyc_date_est as "Timestamp EST of KYC",\n    bc.optintime_ET as "Timestamp EST of Opt In",\n    \n    ts.reached_10_timestamp as "Timestamp EST of $10 Casino Cash Wagering",\n    CASE WHEN "Timestamp EST of $10 Casino Cash Wagering" = NULL THEN False else true end as "Wager Requirement T/F",\n    \n    fsp.day1_awarded  AS "Timestamp EST of Day 1",\n    fsp.day2_awarded  AS "Timestamp EST of Day 2",\n    fsp.day3_awarded  AS "Timestamp EST of Day 3",\n    fsp.day4_awarded  AS "Timestamp EST of Day 4",\n    fsp.day5_awarded  AS "Timestamp EST of Day 5",\n\n\n    CASE WHEN day1_awarded IS NULL THEN FALSE ELSE TRUE END AS day1_awarded_,\n    CASE WHEN day2_awarded IS NULL THEN FALSE ELSE TRUE END AS day2_awarded_,\n    CASE WHEN day3_awarded IS NULL THEN FALSE ELSE TRUE END AS day3_awarded_,\n    CASE WHEN day4_awarded IS NULL THEN FALSE ELSE TRUE END AS day4_awarded_,\n    CASE WHEN day5_awarded IS NULL THEN FALSE ELSE TRUE END AS day5_awarded_,\n\n    fspo.day1_optedin  AS "Timestamp EST of Day 1 Opted In",\n    fspo.day2_optedin  AS "Timestamp EST of Day 2 Opted In",\n    fspo.day3_optedin  AS "Timestamp EST of Day 3 Opted In",\n    fspo.day4_optedin  AS "Timestamp EST of Day 4 Opted In",\n    fspo.day5_optedin  AS "Timestamp EST of Day 5 Opted In",\n\n    CASE WHEN day1_optedin IS NULL THEN FALSE ELSE TRUE END AS day1_optedin_,\n    CASE WHEN day2_optedin IS NULL THEN FALSE ELSE TRUE END AS day2_optedin_,\n    CASE WHEN day3_optedin IS NULL THEN FALSE ELSE TRUE END AS day3_optedin_,\n    CASE WHEN day4_optedin IS NULL THEN FALSE ELSE TRUE END AS day4_optedin_,\n    CASE WHEN day5_optedin IS NULL THEN FALSE ELSE TRUE END AS day5_optedin_,\n\n    CASE WHEN "Wager Requirement T/F" = TRUE AND day2_optedin_ = TRUE AND day2_awarded_ = FALSE THEN TRUE end as day2_missed,\n    CASE WHEN "Wager Requirement T/F" = TRUE AND day3_optedin_ = TRUE AND day3_awarded_ = FALSE THEN TRUE end as day3_missed,\n    CASE WHEN "Wager Requirement T/F" = TRUE AND day4_optedin_ = TRUE AND day4_awarded_ = FALSE THEN TRUE end as day4_missed,\n    CASE WHEN "Wager Requirement T/F" = TRUE AND day5_optedin_ = TRUE AND day5_awarded_ = FALSE THEN TRUE end as day5_missed\n\n\n    \nFROM bonus_campaign_opt_ins bc\nLEFT JOIN timestamp_of_10_stake ts\n    ON bc.acco_id = ts.acco_id\nLEFT JOIN FBG_ANALYTICS_ENGINEERING.CUSTOMERS.customer_mart AS cs\n  ON bc.acco_id = cs.acco_id\nLEFT JOIN free_spin_pivot_optedin as fspo \n    on bc.acco_id = fspo.acco_id\nLEFT JOIN free_spin_pivot_awarded AS fsp\n  ON bc.acco_id = fsp.acco_id\nWHERE cs.is_test_account = 0',NULL,'01c399f4-0212-6b00-24dd-07031931a4bb','Thread-7 (worker)','table','{"_message": "SUCCESS 45080", "code": "SUCCESS", "rows_affected": 45080, "query_id": "01c399f4-0212-6b00-24dd-07031931a4bb", "rows_inserted": 45080, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('0d6fedc4-7351-444c-be2e-615007381edb.model.dbt_casino.casino_suo_1000_free_spins','model.dbt_casino.casino_suo_1000_free_spins','0d6fedc4-7351-444c-be2e-615007381edb','2026-04-09 21:12:35',
