s_id = j.id\n    WHERE a.trans = \'FREE_SPIN_AWARDED\' AND \n    a.bonus_campaign_id IN \n    (\n        -- Day 1\n        \'130966\', \'131574\', \'144546\', \'144553\',\n        -- Day 2\n        \'130967\',\'131580\', \'144547\',\'144554\',\n        -- Day 3\n        \'130968\',\'131604\', \'144548\', \'144555\',\n        -- Day 4\n        \'130969\',\'131607\', \'144549\', \'144556\',\n        -- Day 5\n        \'130970\',\'131610\', \'144550\', \'144557\'\n    )\n),\ncash_wagering AS \n(\n    SELECT \n        cba.acco_id,\n        cba.placed_time_est,\n        cba.stake,\n        SUM(cba.stake) \n          OVER (\n            PARTITION BY cba.acco_id \n            ORDER BY cba.placed_time_est \n            ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW\n          ) AS cumulative_wager\n    FROM FBG_ANALYTICS_ENGINEERING.CASINO.casino_transactions_mart AS cba\n    WHERE cba.fund_type_id = 1\n      AND cba.void = 0\n),\n\ntimestamp_of_10_stake AS\n(\n    SELECT \n        cash_wagering.acco_id,\n        placed_time_est AS reached_10_timestamp,\n        CASE WHEN reached_10_timestamp = NULL THEN FALSE ELSE TRUE end as reached_timestamp \n    \n        \n    FROM cash_wagering\n    WHERE cumulative_wager >= 10\n    QUALIFY ROW_NUMBER() \n      OVER (PARTITION BY cash_wagering.acco_id ORDER BY placed_time_est) = 1\n),\n\nfree_spin_pivot_awarded AS\n(\n    SELECT\n        acco_id,\n        MAX(CASE WHEN bonus_campaign_id IN (\'130966\', \'131574\', \'144546\', \'144553\')  THEN date END) AS day1_awarded,\n        MAX(CASE WHEN bonus_campaign_id IN (\'130967\',\'131580\', \'144547\',\'144554\') THEN date END) AS day2_awarded,\n        MAX(CASE WHEN bonus_campaign_id IN (\'130968\',\'131604\', \'144548\', \'144555\') THEN date END) AS day3_awarded,\n        MAX(CASE WHEN bonus_campaign_id IN (\'130969\',\'131607\', \'144549\', \'144556\') THEN date END) AS day4_awarded,\n        MAX(CASE WHEN bonus_campaign_id IN (\'130970\',\'131610\', \'144550\', \'144557\') THEN date END) AS day5_awarded\n    FROM account_statements_free_spins\n    GROUP BY acco_id\n),\n\nfree_spin_pivot_optedin AS\n(\n\nSELECT\n    acco_id,\n    MAX(CASE WHEN bonus_campaign_id IN (\'130966\', \'131574\', \'144546\', \'144553\') THEN date END) AS day1_optedin,\n    MAX(CASE WHEN bonus_campaign_id IN (\'130967\',\'131580\', \'144547\',\'144554\') THEN date END) AS day2_optedin,\n    MAX(CASE WHEN bonus_campaign_id IN (\'130968\',\'131604\', \'144548\', \'144555\') THEN date END) AS day3_optedin,\n    MAX(CASE WHEN bonus_campaign_id IN (\'130969\',\'131607\', \'144549\', \'144556\') THEN date END) AS day4_optedin,\n    MAX(CASE WHEN bonus_campaign_id IN (\'130970\',\'131610\', \'144550\', \'144557\') THEN date END) AS day5_optedin\n\nFROM \nopt_in_sequenced\ngroup by all \n\n)\n\n\nSELECT\n\n\n    bc.acco_id,\n    bc.bonus_campaign_id,\n    cs.registration_state,\n    cs.acquisition_bonus_name,\n    \n    cs.registration_date_est as "Timestamp EST of Registration",\n    cs.kyc_date_est as "Timestamp EST of KYC",\n    bc.optintime_ET as "Timestamp EST of Opt In",\n    \n    ts.reached_10_timestamp as "Timestamp EST of $10 Casino Cash Wagering",\n    CASE WHEN "Timestamp EST of $10 Casino Cash Wagering" = NULL THEN False else true end as "Wager Requirement T/F",\n    \n    fsp.day1_awarded  AS "Timestamp EST of Day 1",\n    fsp.day2_awarded  AS "Timestamp EST of Day 2",\n    fsp.day3_awarded  AS "Timestamp EST of Day 3",\n    fsp.day4_awarded  AS "Timestamp EST of Day 4",\n    fsp.day5_awarded  AS "Timestamp EST of Day 5",\n\n\n    CASE WHEN day1_awarded IS NULL THEN FALSE ELSE TRUE END AS day1_awarded_,\n    CASE WHEN day2_awarded IS NULL THEN FALSE ELSE TRUE END AS day2_awarded_,\n    CASE WHEN day3_awarded IS NULL THEN FALSE ELSE TRUE END AS day3_awarded_,\n    CASE WHEN day4_awarded IS NULL THEN FALSE ELSE TRUE END AS day4_awarded_,\n    CASE WHEN day5_awarded IS NULL THEN FALSE ELSE TRUE END AS day5_awarded_,\n\n    fspo.day1_optedin  AS "Timestamp EST of Day 1 Opted In",\n    fspo.day2_optedin  AS "Timestamp EST of Day 2 Opted In",\n    fspo.day3_optedin  AS "Timestamp EST of Day 3 Opted In",\n    fspo.day4_optedin  AS "Timestamp EST of Day 4 Opted In",\n    fspo.day5_optedin  AS "Timestamp EST of Day 5 Opted In",\n\n    CASE WHEN day1_optedin IS NULL THEN FALSE ELSE TRUE END AS day1_optedin_,\n    CASE WHEN day2_optedin IS NULL THEN FALSE ELSE TRUE END AS day2_optedin_,\n    CASE WHEN day3_optedin IS NULL THEN FALSE ELSE TRUE END AS day3_optedin_,\n    CASE WHEN day4_optedin IS NULL THEN FALSE ELSE TRUE END AS day4_optedin_,\n    CASE WHEN day5_optedin IS NULL THEN FALSE ELSE TRUE END AS day5_optedin_,\n\n    CASE WHEN "Wager Requirement T/F" = TRUE AND day2_optedin_ = TRUE AND day2_awarded_ = FALSE THEN TRUE end as day2_missed,\n    CASE WHEN "Wager Requirement T/F" = TRUE AND day3_optedin_ = TRUE AND day3_awarded_ = FALSE THEN TRUE end as day3_missed,\n    CASE WHEN "Wager Requirement T/F" = TRUE AND day4_optedin_ = TRUE AND day4_awarded_ = FALSE THEN TRUE end as day4_missed,\n    CASE WHEN "Wager Requirement T/F" = TRUE AND day5_optedin_ = TRUE AND day5_awarded_ = FALSE THEN TRUE end as day5_missed\n\n\n    \nFROM bonus_campaign_opt_ins bc\nLEFT JOIN timestamp_of_10_stake ts\n    ON bc.acco_id = ts.acco_id\nLEFT JOIN FBG_ANALYTICS_ENGINEERING.CUSTOMERS.customer_mart AS cs\n  ON bc.acco_id = cs.acco_id\nLEFT JOIN free_spin_pivot_optedin as fspo \n    on bc.acco_id = fspo.acco_id\nLEFT JOIN free_spin_pivot_awarded AS fsp\n  ON bc.acco_id = fsp.acco_id\nWHERE cs.is_test_account = 0',NULL,'01c399f4-0212-6b00-24dd-07031931a4bf','Thread-6 (worker)','table','{"_message": "SUCCESS 18660", "code": "SUCCESS", "rows_affected": 18660, "query_id": "01c399f4-0212-6b00-24dd-07031931a4bf", "rows_inserted": 18660, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('0d6fedc4-7351-444c-be2e-615007381edb.model.dbt_casino.reporting_suo_dual_product','model.dbt_casino.reporting_suo_dual_product','0d6fedc4-7351-444c-be2e-615007381edb','2026-04-09 21:12:35',
  current_timestamp::timestamp
,'reporting_suo_dual_product','SUCCESS 4160','success','model',75.59025168418884,'2026-04-09T21:10:18.702893Z','2026-04-09T21:11:34.149463Z','2026-04-09T21:10:18.695330Z','2026-04-09T21:10:18.701941Z',4160,False,'with bonus_opt_ins as (\n    select\n        acco_id,\n        bonus_campaign_id,\n        max(convert_timezone(\'UTC\', \'America/New_York\',to_timestamp_ntz(try_to_number(split_part(split_part(overrides, \'optInTime=\', 2), \';\', 1)), 3))) as optin_time_et,\n    from FBG_SOURCE.OSB_SOURCE.ACCOUNT_BONUSES\n    where bonus_campaign_id in (203064, 203067, 203079, 203099, 203100, 203101, -- PA bonus\n                                203106, 203109, 203110, 203631, 203632, 203633, 203634, 203635) -- MI Bonus\n    group by all\n),\n\nbonus_opt_in_pivot as (\n    select\n        acco_id,\n        --PA\n        --max(case when bonus_campaign_id = 203064 then optin_time_et end) as Day1_OSB_FC_Optin_PA,\n        max(case when bonus_campaign_id = 203067 then optin_time_et end) as Day2_OSB_FC_Optin_PA,\n        max(case when bonus_campaign_id = 203079 then optin_time_et end) as Day3_OSB_FC_Optin_PA,\n        --max(case when bonus_campaign_id = 203099 then optin_time_et end) as Day1_OC_CC_Optin_PA,\n        max(case when bonus_campaign_id = 203100 then optin_time_et end) as Day2_OC_CC_Optin_PA,\n        max(case when bonus_campaign_id = 203101 then optin_time_et end) as Day3_OC_CC_Optin_PA,\n        --MI\n        --max(case when bonus_campaign_id = 203106 then optin_time_et end) as Day1_OSB_FC_Optin_MI,\n        max(case when bonus_campaign_id = 203109 then optin_time_et end) as Day2_OSB_FC_Optin_MI,\n        max(case when bonus_campaign_id = 203110 then optin_time_et end) as Day3_OSB_FC_Optin_MI,\n        --max(case when bonus_campaign_id = 203631 then optin_time_et end) as Day1_OC_FS_Optin_MI,\n        max(case when bonus_campaign_id = 203632 then optin_time_et end) as Day2_OC_FS_Optin_MI,\n        max(case when bonus_campaign_id = 203633 then optin_time_et end) as Day3_OC_FS_Optin_MI,\n        max(case when bonus_campaign_id = 203634 then optin_time_et end) as Day4_OC_FS_Optin_MI,\n        max(case when bonus_campaign_id = 203635 then optin_time_et end) as Day5_OC_FS_Optin_MI\n    from bonus_opt_ins\n    group by all\n),\n\noc_cc_fs_awarded as (\n    select\n        acco_id,\n        coalesce(cast(nullif(ext_bonus_campaign_id, \'\') as int), bonus_campaign_id) as bonus_campaign_id,\n        max(convert_timezone(\'UTC\',\'America/New_York\', trans_date)) as award_timestamp_et\n    from FBG_SOURCE.OSB_SOURCE.ACCOUNT_STATEMENTS\n    where trans in (\'CASINO_CREDIT_AWARDED\', \'FREE_SPIN_AWARDED\')\n    and bonus_campaign_id in (203099, 203100, 203101, 203631, 203632, 203633, 203634, 203635)\n    group by all\n),\n\noc_cc_fs_awarded_pivot as (\n    select\n        acco_id,\n        --PA\n        max(case when bonus_campaign_id = 203099 then award_timestamp_et end) as Day1_OC_CC_Award_PA,\n        max(case when bonus_campaign_id = 203100 then award_timestamp_et end) as Day2_OC_CC_Award_PA,\n        max(case when bonus_campaign_id = 203101 then award_timestamp_et end) as Day3_OC_CC_Award_PA,\n        --MI\n        max(case when bonus_campaign_id = 203631 then award_timestamp_et end) as Day1_OC_FS_Award_MI,\n        max(case when bonus_campaign_id = 203632 then award_timestamp_et end) as Day2_OC_FS_Award_MI,\n        max(case when bonus_campaign_id = 203633 then award_timestamp_et end) as Day3_OC_FS_Award_MI,\n        max(case when bonus_campaign_id = 203634 then award_timestamp_et end) as Day4_OC_FS_Award_MI,\n        max(case when bonus_campaign_id = 203635 then award_timestamp_et end) as Day5_OC_FS_Award_MI\n    from oc_cc_fs_awarded\n    group by all\n),\n\nosb_fc_awarded as (\n    select \n        ats_account_id as acco_id,\n        bonus_campaign,\n        max(convert_timezone(\'UTC\',\'America/New_York\', created_date)) as fc_award_timestamp_et\n    from FBG_SOURCE.FANX_MONGODB.FANCASH\n    where transaction_type = \'EARN\'\n    and status = \'SETTLED\'\n    and bonus_campaign in (203064, 203067, 203079, -- PA bonus\n                           203106, 203109, 203110) -- MI Bonus\n    group by all\n),\n\nosb_fc_awarded_pivot as (\n    select\n        acco_id,\n        --PA\n        max(case when bonus_campaign = 203064 then fc_award_timestamp_et end) as Day1_OSB_FC_Award_PA,\n        max(case when bonus_campaign = 203067 then fc_award_timestamp_et end) as Day2_OSB_FC_Award_PA,\n        max(case when bonus_campaign = 203079 then fc_award_timestamp_et end) as Day3_OSB_FC_Award_PA,\n        --MI\n        max(case when bonus_campaign = 203106 then fc_award_timestamp_et end) as Day1_OSB_FC_Award_MI,\n        max(case when bonus_campaign = 203109 then fc_award_timestamp_et end) as Day2_OSB_FC_Award_MI,\n        max(case when bonus_campaign = 203110 then fc_award_timestamp_et end) as Day3_OSB_FC_Award_MI\n    from osb_fc_awarded\n    group by all\n),\n\noc_wagering_cumulative as (\n    select \n        acco_id,\n        placed_time_est,\n        stake,\n        sum(stake) over (partition by acco_id order by placed_time_est) as cumulative_wager\n    from FBG_ANALYTICS_ENGINEERING.CASINO.CASINO_TRANSACTIONS_MART\n    where fund_type_id = 1 \n    and void = 0\n),\n\noc_wagering_pivot as (\n    select\n        acco_id,\n        min(case when cumulative_wager >= 10 then placed_time_est else NULL end) as oc_wager_10_timestamp_et,\n        min(case when cumulative_wager >= 30 then placed_time_est else NULL end) as oc_wager_30_timestamp_et\n    from oc_wagering_cumulative\n    group by all\n),\n\nosb_wagering as (\n    select \n        account_id as acco_id,\n        convert_timezone(\'UTC\',\'America/New_York\', wager_settlement_time_utc) as osb_settled_timestamp_et\n    from FBG_ANALYTICS_ENGINEERING.TRADING.TRADING_SPORTSBOOK_MART\n    where wager_status = \'SETTLED\'\n    and wager_channel = \'INTERNET\'\n    and is_free_bet_wager = 0\n    and total_price_by_wager >= 1.2\n    and total_cash_stake_by_wager >= 10\n    and date(convert_timezone(\'UTC\',\'America/New_York\', wager_placed_time_utc)) = \n        date(convert_timezone(\'UTC\',\'America/New_York\', wager_settlement_time_utc))\n    qualify row_number() over (\n                               partition by account_id, date(osb_settled_timestamp_et) \n                               order by wager_settlement_time_utc\n                               ) = 1\n),\n\nosb_wagering_pivot as (\n    select\n        a.acco_id,\n        max(case when date(a.osb_settled_timestamp_et) = date(b.registration_date_est) \n             then osb_settled_timestamp_et \n             else null \n             end) as Day1_OSB_Wager,\n        max(case when date(a.osb_settled_timestamp_et) = dateadd(day, 1, date(b.registration_date_est)) \n             then osb_settled_timestamp_et \n             else null \n             end) as Day2_OSB_Wager,\n        max(case when date(a.osb_settled_timestamp_et) = dateadd(day, 2, date(b.registration_date_est)) \n             then osb_settled_timestamp_et \n             else null \n             end) as Day3_OSB_Wager,\n    from osb_wagering a\n    left join FBG_ANALYTICS_ENGINEERING.CUSTOMERS.CUSTOMER_MART b on a.acco_id = b.acco_id\n    group by all\n),\n\nsummarise_join as (\n    select\n    a.*,\n    b.acquisition_bonus_name,\n    b.registration_date_est as reg_timestamp,\n    b.kyc_date_est as kyc_timestamp,\n    c.* exclude (acco_id),\n    d.* exclude (acco_id),\n    case when date(e.oc_wager_10_timestamp_et) < dateadd(day, 7, date(b.registration_date_est)) \n         then e.oc_wager_10_timestamp_et\n         else null\n         end as OC_Wager_10_MI,\n    case when date(e.oc_wager_30_timestamp_et) < dateadd(day, 7, date(b.registration_date_est)) \n         then e.oc_wager_30_timestamp_et\n         else null\n         end as OC_Wager_30_PA,\n    f.* exclude (acco_id)\n    from bonus_opt_in_pivot a\n    inner join FBG_ANALYTICS_ENGINEERING.CUSTOMERS.CUSTOMER_MART b on a.acco_id = b.acco_id\n    left join oc_cc_fs_awarded_pivot c on a.acco_id = c.acco_id\n    left join osb_fc_awarded_pivot d on a.acco_id = d.acco_id\n    left join oc_wagering_pivot e on a.acco_id = e.acco_id\n    left join osb_wagering_pivot f on a.acco_id = f.acco_id\n    where b.is_test_account = 0\n)\n\nselect * from summarise_join',NULL,'01c399f6-0212-6e7d-24dd-07031931cd27','Thread-9 (worker)','table','{"_message": "SUCCESS 4160", "code": "SUCCESS", "rows_affected": 4160, "query_id": "01c399f6-0212-6e7d-24dd-07031931cd27", "rows_inserted": 4160, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('0d6fedc4-7351-444c-be2e-615007381edb.model.dbt_casino.casino_suo_500fs','model.dbt_casino.casino_suo_500fs','0d6fedc4-7351-444c-be2e-615007381edb','2026-04-09 21:12:35',
  current_timestamp::timestamp
,'casino_suo_500fs','SUCCESS 157286','success','model',111.43348264694214,'2026-04-09T21:09:47.721367Z','2026-04-09T21:11:39.062035Z','2026-04-09T21:09:47.716257Z','2026-04-09T21:09:47.720793Z',157286,False,'WITH bonus_campaign_opt_ins AS ---Reg ID\n(\n    SELECT DISTINCT \n        acco_id,\n        bonus_campaign_id,\n        CONVERT_TIMEZONE(\'UTC\',\'America/New_York\',\n            TO_TIMESTAMP(\n              SUBSTR(overrides, REGEXP_INSTR(overrides,\'optInTime\')+10,13)\n            )\n        ) AS optintime_ET,\n        CASE WHEN state <> \'AVAILABLE\' THEN acco_id ELSE NULL END AS opt_in\n    FROM FBG_SOURCE.OSB_SOURCE.ACCOUNT_BONUSES\n    WHERE bonus_campaign_id IN (\'71809\',\'65876\',\'75238\',\'65874\',\'74380\',\'65875\',\'71106\',\'64150\', \'119262\') AND OVERRIDES LIKE \'%optInTime%\'\n),\n\nopt_in_sequenced as \n(\n\nSELECT\n    acco_id,\n    bonus_campaign_id,\n    CONVERT_TIMEZONE(\'UTC\',\'America/New_York\', TO_TIMESTAMP(SUBSTR(overrides, REGEXP_INSTR(overrides,\'optInTime\')+10,13))) AS date,\nFROM \nFBG_SOURCE.OSB_SOURCE.ACCOUNT_BONUSES a\nWHERE \na.bonus_campaign_id IN (\n        -- Day 1\n        \'64156\',\'65853\',\'65855\',\'65863\',\n        -- Day 2\n        \'63861\',\'65554\',\'65819\',\'65844\',\n        -- Day 3\n        \'63863\',\'65553\',\'65826\',\'65842\',\n        -- Day 4\n        \'63867\',\'65552\',\'65827\',\'65839\',\n        -- Day 5\n        \'63870\',\'65551\',\'65829\',\'65838\',\n        -- Day 6\n        \'63866\',\'65550\',\'65850\',\'65835\',\n        -- Day 7\n        \'63859\',\'65549\',\'65843\',\'65833\',\n        -- Day 8\n        \'63856\',\'65548\',\'65845\',\'65831\',\n        -- Day 9\n        \'63853\',\'65547\',\'65846\',\'65848\',\n        -- Day 10\n        \'63862\',\'65546\',\'65847\',\'65815\'\n        )\nAND state <> \'AVAILABLE\' AND OVERRIDES LIKE \'%optInTime%\'\n),\naccount_statements_free_spins\nAS\n(\n    SELECT\n        a.acco_id,\n        COALESCE(\n          CAST(NULLIF(a.ext_bonus_campaign_id,\'\') AS INT),\n          a.bonus_campaign_id\n        ) AS bonus_campaign_id,\n        CONVERT_TIMEZONE(\'UTC\',\'America/New_York\', a.trans_date) AS date\n    FROM FBG_SOURCE.OSB_SOURCE.ACCOUNT_STATEMENTS AS a\n    INNER JOIN FBG_SOURCE.OSB_SOURCE.JURISDICTIONS AS j\n        ON a.jurisdictions_id = j.id\n    WHERE a.trans = \'FREE_SPIN_AWARDED\' AND \n    a.bonus_campaign_id IN \n    (\n        -- Day 1\n        \'64156\',\'65853\',\'65855\',\'65863\',\n        -- Day 2\n        \'63861\',\'65554\',\'65819\',\'65844\',\n        -- Day 3\n        \'63863\',\'65553\',\'65826\',\'65842\',\n        -- Day 4\n        \'63867\',\'65552\',\'65827\',\'65839\',\n        -- Day 5\n        \'63870\',\'65551\',\'65829\',\'65838\',\n        -- Day 6\n        \'63866\',\'65550\',\'65850\',\'65835\',\n        -- Day 7\n        \'63859\',\'65549\',\'65843\',\'65833\',\n        -- Day 8\n        \'63856\',\'65548\',\'65845\',\'65831\',\n        -- Day 9\n        \'63853\',\'65547\',\'65846\',\'65848\',\n        -- Day 10\n        \'63862\',\'65546\',\'65847\',\'65815\'\n      )\n),\n\naccount_statements_date_of_bonus as\n(\n    SELECT\n        a.acco_id,\n        a.id as account_statements_id,\n        COALESCE(cast(replace(a.ext_bonus_campaign_id,\'\',null) as int),a.bonus_campaign_id) as bonus_campaign_id,\n        try_parse_json(a.additional_info):bonusOrigin::varchar as "Bonus Origin", \n        (convert_timezone(\'UTC\', \'America/New_York\', trans_date)) AS date,\n        case when a.trans = \'CASINO_CREDIT_AWARDED\' then \'bonus awarded\'\n             when a.trans = \'CASINO_CREDIT_STAKE\' then \'bonus used\' end as transaction,\n        \'casino_credit\' as promo_type,\n        abs(a.amount) amount,\n        a.bet_id,\n        parse_json(a.additional_info):accountBonusId::int as account_bonus_id\n    FROM FBG_SOURCE.OSB_SOURCE.ACCOUNT_STATEMENTS AS a\n    INNER JOIN FBG_SOURCE.OSB_SOURCE.JURISDICTIONS AS j\n        on a.jurisdictions_id = j.id\n    LEFT JOIN FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.BONUS_CATEGORIES AS B\n        ON COALESCE(cast(replace(a.ext_bonus_campaign_id,\'\',null) as int),a.bonus_campaign_id) = b.bonus_campaign_id\n    WHERE a.trans in (\'FREE_SPIN_AWARDED\')\n        and a.bonus_campaign_id IN (\'65863\', \'65853\', \'65855\', \'64156\')\n),\ncash_wagering AS \n(\n    SELECT \n        cba.acco_id,\n  ---      oi.bonus_campaign_id,\n        cba.placed_time_est,\n  --      oi.optintime_ET,\n        cba.stake,\n        SUM(cba.stake) \n          OVER (\n            PARTITION BY cba.acco_id \n            ORDER BY cba.placed_time_est \n            ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW\n          ) AS cumulative_wager\n    FROM\n    FBG_ANALYTICS_ENGINEERING.CASINO.casino_transactions_mart AS cba\n    WHERE cba.fund_type_id = 1\n      AND cba.void = 0\n),\n\ntimestamp_of_10_stake AS\n(\n    SELECT \n        acco_id,\n  --      optintime_ET,\n  --      bonus_campaign_id,\n        placed_time_est AS reached_10_timestamp\n    FROM cash_wagering\n    WHERE cumulative_wager >= 10\n    QUALIFY ROW_NUMBER() \n      OVER (PARTITION BY acco_id ORDER BY placed_time_est) = 1\n),\n\nfree_spin_pivot_optedin as\n(\n\nSELECT\n    acco_id,\n    MAX(CASE WHEN bonus_campaign_id IN (\'64156\',\'65853\',\'65855\',\'65863\') THEN date ELSE NULL END) AS day1_optedin,\n    MAX(CASE WHEN bonus_campaign_id IN (\'63861\',\'65554\',\'65819\',\'65844\') THEN date ELSE NULL END) AS day2_optedin,\n    MAX(CASE WHEN bonus_campaign_id IN (\'63863\',\'65553\',\'65826\',\'65842\') THEN date ELSE NULL END) AS day3_optedin,\n    MAX(CASE WHEN bonus_campaign_id IN (\'63867\',\'65552\',\'65827\',\'65839\') THEN date ELSE NULL END) AS day4_optedin,\n    MAX(CASE WHEN bonus_campaign_id IN (\'63870\',\'65551\',\'65829\',\'65838\') THEN date ELSE NULL END) AS day5_optedin,\n    MAX(CASE WHEN bonus_campaign_id IN (\'63866\',\'65550\',\'65850\',\'65835\') THEN date ELSE NULL END) AS day6_optedin,\n    MAX(CASE WHEN bonus_campaign_id IN (\'63859\',\'65549\',\'65843\',\'65833\') THEN date ELSE NULL END) AS day7_optedin,\n    MAX(CASE WHEN bonus_campaign_id IN (\'63856\',\'65548\',\'65845\',\'65831\') THEN date ELSE NULL END) AS day8_optedin,\n    MAX(CASE WHEN bonus_campaign_id IN (\'63853\',\'65547\',\'65846\',\'65848\') THEN date ELSE NULL END) AS day9_optedin,\n    MAX(CASE WHEN bonus_campaign_id IN (\'63862\',\'65546\',\'65847\',\'65815\') THEN date ELSE NULL END) AS day10_optedin\n\nFROM\nopt_in_sequenced\nGROUP BY ALL \n\n),\nfree_spin_pivot_awarded AS\n(\n    SELECT\n        acco_id,\n        MAX(CASE WHEN bonus_campaign_id IN (\'64156\',\'65853\',\'65855\',\'65863\') THEN date END) AS day1_awarded,\n        MAX(CASE WHEN bonus_campaign_id IN (\'63861\',\'65554\',\'65819\',\'65844\') THEN date END) AS day2_awarded,\n        MAX(CASE WHEN bonus_campaign_id IN (\'63863\',\'65553\',\'65826\',\'65842\') THEN date END) AS day3_awarded,\n        MAX(CASE WHEN bonus_campaign_id IN (\'63867\',\'65552\',\'65827\',\'65839\') THEN date END) AS day4_awarded,\n        MAX(CASE WHEN bonus_campaign_id IN (\'63870\',\'65551\',\'65829\',\'65838\') THEN date END) AS day5_awarded,\n        MAX(CASE WHEN bonus_campaign_id IN (\'63866\',\'65550\',\'65850\',\'65835\') THEN date END) AS day6_awarded,\n        MAX(CASE WHEN bonus_campaign_id IN (\'63859\',\'65549\',\'65843\',\'65833\') THEN date END) AS day7_awarded,\n        MAX(CASE WHEN bonus_campaign_id IN (\'63856\',\'65548\',\'65845\',\'65831\') THEN date END) AS day8_awarded,\n        MAX(CASE WHEN bonus_campaign_id IN (\'63853\',\'65547\',\'65846\',\'65848\') THEN date END) AS day9_awarded,\n        MAX(CASE WHEN bonus_campaign_id IN (\'63862\',\'65546\',\'65847\',\'65815\') THEN date END) AS day10_awarded\n    FROM account_statements_free_spins\n    GROUP BY acco_id\n)\n\nSELECT\n\n    bc.acco_id,\n    bc.bonus_campaign_id,\n    cs.acquisition_bonus_name,\n    \n    cs.registration_date_est as "Timestamp EST of Registration",\n    cs.kyc_date_est as "Timestamp EST of KYC",\n    bc.optintime_ET as "Timestamp EST of Opt In",\n    \n    ts.reached_10_timestamp as "Timestamp EST of $10 Casino Cash Wagering",\n\n    CASE WHEN "Timestamp EST of $10 Casino Cash Wagering" = NULL THEN FALSE ELSE TRUE END as "Wager Requirement T/F",\n    \n    -- fsp.day1_awarded  AS "Timestamp EST of Day 1",\n    -- fsp.day2_awarded  AS "Timestamp EST of Day 2",\n    -- fsp.day3_awarded  AS "Timestamp EST of Day 3",\n    -- fsp.day4_awarded  AS "Timestamp EST of Day 4",\n    -- fsp.day5_awarded  AS "Timestamp EST of Day 5",\n    -- fsp.day6_awarded  AS "Timestamp EST of Day 6",\n    -- fsp.day7_awarded  AS "Timestamp EST of Day 7",\n    -- fsp.day8_awarded  AS "Timestamp EST of Day 8",\n    -- fsp.day9_awarded  AS "Timestamp EST of Day 9",\n    -- fsp.day10_awarded AS "Timestamp EST of Day 10",\n\n\n    CASE WHEN day1_awarded IS NULL THEN FALSE ELSE TRUE END AS day1_awarded,\n    CASE WHEN day2_awarded IS NULL THEN FALSE ELSE TRUE END AS day2_awarded,\n    CASE WHEN day3_awarded IS NULL THEN FALSE ELSE TRUE END AS day3_awarded,\n    CASE WHEN day4_awarded IS NULL THEN FALSE ELSE TRUE END AS day4_awarded,\n    CASE WHEN day5_awarded IS NULL THEN FALSE ELSE TRUE END AS day5_awarded,\n    CASE WHEN day6_awarded IS NULL THEN FALSE ELSE TRUE END AS day6_awarded,\n    CASE WHEN day7_awarded IS NULL THEN FALSE ELSE TRUE END AS day7_awarded,\n    CASE WHEN day8_awarded IS NULL THEN FALSE ELSE TRUE END AS day8_awarded,\n    CASE WHEN day9_awarded IS NULL THEN FALSE ELSE TRUE END AS day9_awarded,\n    CASE WHEN day10_awarded IS NULL THEN FALSE ELSE TRUE END AS day10_awarded,\n\n    CASE WHEN day1_optedin IS NULL THEN FALSE ELSE TRUE END AS day1_optedin,\n    CASE WHEN day2_optedin  IS NULL THEN FALSE ELSE TRUE END AS day2_optedin,\n    CASE WHEN day3_optedin  IS NULL THEN FALSE ELSE TRUE END AS day3_optedin,\n    CASE WHEN day4_optedin  IS NULL THEN FALSE ELSE TRUE END AS day4_optedin,\n    CASE WHEN day5_optedin  IS NULL THEN FALSE ELSE TRUE END AS day5_optedin,\n    CASE WHEN day6_optedin  IS NULL THEN FALSE ELSE TRUE END AS day6_optedin,\n    CASE WHEN day7_optedin  IS NULL THEN FALSE ELSE TRUE END AS day7_optedin,\n    CASE WHEN day8_optedin  IS NULL THEN FALSE ELSE TRUE END AS day8_optedin,\n    CASE WHEN day9_optedin  IS NULL THEN FALSE ELSE TRUE END AS day9_optedin,\n    CASE WHEN day10_optedin IS NULL THEN FALSE ELSE TRUE END AS day10_optedin\n\n    \n   \nFROM bonus_campaign_opt_ins bc\nLEFT JOIN timestamp_of_10_stake ts\n    ON bc.acco_id = ts.acco_id\nLEFT JOIN FBG_ANALYTICS_ENGINEERING.CUSTOMERS.customer_mart  AS cs\n    ON ts.acco_id = cs.acco_id\nLEFT JOIN account_statements_date_of_bonus ab\n    on ab.acco_id = ts.acco_id\nLEFT JOIN free_spin_pivot_optedin fsa\n    on fsa.acco_id = ts.acco_id\nLEFT JOIN free_spin_pivot_awarded AS fsp\n  ON ts.acco_id = fsp.acco_id\nWHERE cs.is_test_account = 0 \n----AND acquisition_bonus_name = \'Casino Wager $10 Get 500 Free Spins Sequenced\'\nAND bc.bonus_campaign_id IN (\'71809\',\'65876\',\'75238\',\'65874\',\'74380\',\'65875\',\'71106\',\'64150\', \'119262\')',NULL,'01c399f5-0212-6b00-24dd-07031931ac33','Thread-8 (worker)','table','{"_message": "SUCCESS 157286", "code": "SUCCESS", "rows_affected": 157286, "query_id": "01c399f5-0212-6b00-24dd-07031931ac33", "rows_inserted": 157286, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('0d6fedc4-7351-444c-be2e-615007381edb.model.dbt_casino.fancash_jackpot_optin_hourly_report','model.dbt_casino.fancash_jackpot_optin_hourly_report','0d6fedc4-7351-444c-be2e-615007381edb','2026-04-09 21:12:35',
  current_timestamp::timestamp
,'fancash_jackpot_optin_hourly_report','SUCCESS 18552','success','model',94.66038489341736,'2026-04-09T21:10:50.000547Z','2026-04-09T21:12:24.543005Z','2026-04-09T21:10:49.997159Z','2026-04-09T21:10:49.999982Z',18552,False,'-- timestamps in EST for CRM and CS teams\nWITH calendar_days AS (\n    SELECT CALENDAR_DATE\n    FROM FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.T_CALENDAR\n    WHERE CALENDAR_DATE >= \'2025-11-19\' -- first day that fcjp starts gradual rollout\n    and year(CALENDAR_DATE) <= 2027\n)\n\n,hours_skeleton AS (\n    SELECT\n        d.CALENDAR_DATE,\n        DATEADD(hour, h.hr, d.CALENDAR_DATE)                                                    AS calendar_hour,\n        /* hour cutoffs (computed once) */\n        DATE_TRUNC(\'hour\', CONVERT_TIMEZONE(\'UTC\',\'America/New_York\', CURRENT_TIMESTAMP()))      AS now_hour_est,\n        DATE_TRUNC(\'hour\', CONVERT_TIMEZONE(\'UTC\',\'America/Anchorage\', CURRENT_TIMESTAMP()))     AS now_hour_alk\n    FROM calendar_days d\n    CROSS JOIN (\n        SELECT ROW_NUMBER() OVER (ORDER BY SEQ4()) - 1 AS hr\n        FROM TABLE(GENERATOR(ROWCOUNT => 24))\n    ) h\n)\n\n\n,base AS (\n    SELECT\n        acco_id,\n        jackpot_group_id,\n        is_opted_in,\n        start_opt_in_timestamp_alk,\n        end_opt_in_timestamp_alk,\n        start_opt_in_timestamp_est,\n        end_opt_in_timestamp_est,\n        first_opt_in_flag,\n        winback_flag,\n        first_opt_in_flag_est,\n        winback_flag_est\n    \n    FROM FBG_ANALYTICS.CASINO.fancash_jackpot_group_optin_history\n    WHERE jackpot_group_id = \'h2hDbKqN\'\n)\n\n\n-- join each hour to the ranges where the user is opted in\n, hourly_stats AS (\n    SELECT \n        h.calendar_date,\n        h.calendar_hour,\n        b.jackpot_group_id,\n        h.now_hour_alk,\n        h.now_hour_est,\n\n        /* ALK view */\n        --currently opted in users at this hour\n        COUNT(DISTINCT CASE\n            WHEN (b.is_opted_in\n                 AND (h.calendar_hour >= b.start_opt_in_timestamp_alk AND h.calendar_hour < b.end_opt_in_timestamp_alk)\n                 AND (h.calendar_hour <= h.now_hour_alk)\n                 )\n            THEN b.acco_id\n        END)                                                                                                                        AS currently_opted_in_users_alk,\n\n        -- newly opted in users (first-ever opt-in) at this hour\n        COUNT(DISTINCT CASE\n            WHEN b.first_opt_in_flag = 1\n                 -- "new opt-in" as happening at the hour of the start timestamp\n                 AND DATE_TRUNC(\'hour\', b.start_opt_in_timestamp_alk) = h.calendar_hour\n            THEN b.acco_id\n        END)                                                                                                                        AS newly_opted_in_users_alk,\n\n        -- winback users (re-opt-ins) at this hour\n        COUNT(DISTINCT CASE\n            WHEN b.winback_flag = 1\n                 AND DATE_TRUNC(\'hour\', b.start_opt_in_timestamp_alk) = h.calendar_hour\n            THEN b.acco_id\n        END)                                                                                                                        AS winback_users_alk,\n\n          /* EST view */\n        --currently opted in users at this hour\n        COUNT(DISTINCT CASE\n            WHEN (b.is_opted_in\n                 AND (h.calendar_hour >= b.start_opt_in_timestamp_est AND h.calendar_hour < b.end_opt_in_timestamp_est)\n                 AND (h.calendar_hour <= h.now_hour_est)\n                )\n            THEN b.acco_id\n        END)                                                                                                                        AS currently_opted_in_users_est,\n\n        -- newly opted in users (first-ever opt-in) at this hour\n        COUNT(DISTINCT CASE\n            WHEN b.first_opt_in_flag_est = 1\n                 -- treat the "new opt-in" as happening at the hour of the start timestamp\n                 AND DATE_TRUNC(\'hour\', b.start_opt_in_timestamp_est) = h.calendar_hour\n            THEN b.acco_id\n        END)                                                                                                                        AS newly_opted_in_users_est,\n\n        -- winback users (re-opt-ins) at this hour\n        COUNT(DISTINCT CASE\n            WHEN b.winback_flag_est = 1\n                 AND DATE_TRUNC(\'hour\', b.start_opt_in_timestamp_est) = h.calendar_hour\n            THEN b.acco_id\n        END)                                                                                                                        AS winback_users_est\n\n    FROM hours_skeleton h\n    LEFT JOIN base b\n      ON (\n          /* join for “currently opted in” in either timezone */\n          (h.calendar_hour >= b.start_opt_in_timestamp_est AND h.calendar_hour < b.end_opt_in_timestamp_est)\n       OR (h.calendar_hour >= b.start_opt_in_timestamp_alk AND h.calendar_hour < b.end_opt_in_timestamp_alk)\n       OR (DATE_TRUNC(\'hour\', b.start_opt_in_timestamp_est) = h.calendar_hour) -- for new/winback users\n       OR (DATE_TRUNC(\'hour\', b.start_opt_in_timestamp_alk) = h.calendar_hour)\n     )\n           \n    GROUP BY ALL\n\n    ORDER by calendar_date, calendar_hour\n)\n\nSELECT\n  *\nFROM hourly_stats',NULL,'01c399f6-0212-6dbe-24dd-07031932b0e7','Thread-7 (worker)','table','{"_message": "SUCCESS 18552", "code": "SUCCESS", "rows_affected": 18552, "query_id": "01c399f6-0212-6dbe-24dd-07031932b0e7", "rows_inserted": 18552, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}')
